import collections

def analyze_retro_trends(
    items_across_launches: list[dict],
) -> dict:
    """
    Analyzes retrospective action items across multiple launches.
    Returns category distribution and recurring root causes.
    """
    category_counts = collections.Counter(
        item["category"] for item in items_across_launches
    )
    # Find categories that appear in > 50% of launches
    launches = {item["feature_id"] for item in items_across_launches}
    category_by_launch = collections.defaultdict(set)
    for item in items_across_launches:
        category_by_launch[item["category"]].add(item["feature_id"])

    systemic = {
        cat: len(launches_with_cat) / len(launches)
        for cat, launches_with_cat in category_by_launch.items()
        if len(launches_with_cat) / len(launches) >= 0.5
    }

    # Find items that closed without updating a template (missed opportunity)
    non_recurring_in_process_gap = [
        item for item in items_across_launches
        if item["category"] == "process_gap" and not item.get("recurring", False)
        and item.get("status") == "done"
    ]

    return {
        "total_items": len(items_across_launches),
        "launches_analyzed": len(launches),
        "category_distribution": dict(category_counts),
        "systemic_categories": systemic,
        "process_gaps_not_codified": len(non_recurring_in_process_gap),
        "recommendation": (
            "Create a program-level initiative to address systemic categories: "
            + ", ".join(systemic.keys())
        ) if systemic else "No systemic patterns detected yet",
    }
